467→void ALFPWorldMapPlayerController::EnterBattle(ALFPWorldMapNode* BattleNode)
468→{
469→	if (!BattleNode) return;
470→
471→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
472→	if (!GI) return;
473→
474→	ALFPWorldMapManager* Manager = GetWorldMapManager();
475→	if (!Manager) return;
476→
477→	// 保存世界地图快照
478→	FLFPWorldMapSnapshot Snapshot;
479→	Snapshot.WorldMapName = Manager->GetCurrentWorldMapName();
480→	if (ULFPWorldMapPlayerState* PS = Manager->GetPlayerState())
481→	{
482→		Snapshot.CurrentNodeID = PS->CurrentNodeID;
483→		Snapshot.CurrentTurn = PS->CurrentTurn;
484→		Snapshot.VisitedNodeIDs = PS->VisitedNodeIDs;
485→		Snapshot.RevealedNodeIDs = PS->RevealedNodeIDs;
486→	}
487→
488→	// 收集已触发节点
489→	for (const auto& Pair : Manager->GetNodeMap())
490→	{
491→		if (Pair.Value && Pair.Value->bHasBeenTriggered)
492→		{
493→			Snapshot.TriggeredNodeIDs.Add(Pair.Key);
494→		}
495→	}
496→
497→	GI->SaveWorldMapSnapshot(Snapshot);
498→
499→	// 设置战斗请求
500→	FLFPBattleRequest Request;
501→	Request.SourceNodeID = BattleNode->NodeID;
502→	Request.BattleMapName = BattleNode->BattleMapName;
503→	Request.StarRating = BattleNode->StarRating;
504→	Request.bCanEscape = BattleNode->bCanEscape;
505→	Request.BaseGoldReward = BattleNode->BaseGoldReward;
506→	Request.BaseFoodReward = BattleNode->BaseFoodReward;
507→	GI->SetBattleRequest(Request);
