30→void ALFPWorldMapPawn::MoveToLocation(FVector TargetLocation)
31→{
32→	if (bIsMoving) return;
33→	if (!MoveCurve)
34→	{
35→		// 没有曲线，直接瞬移
36→		SetActorLocation(TargetLocation);
37→		OnMoveComplete.Broadcast();
38→		return;
39→	}
40→
41→	bIsMoving = true;
42→	MoveStartLocation = GetActorLocation();
43→	MoveTargetLocation = TargetLocation;
44→
45→	// 设置 Timeline
46→	FOnTimelineFloat UpdateCallback;
47→	UpdateCallback.BindUFunction(this, FName("UpdateMoveAnimation"));
48→
49→	FOnTimelineEvent FinishedCallback;
50→	FinishedCallback.BindUFunction(this, FName("OnMoveFinished"));
51→
52→	MoveTimeline.AddInterpFloat(MoveCurve, UpdateCallback);
53→	MoveTimeline.SetTimelineFinishedFunc(FinishedCallback);
54→	MoveTimeline.SetPlayRate(1.0f / MoveDuration);
55→	MoveTimeline.PlayFromStart();
56→}
