69→void ALFPWorldMapPawn::OnMoveFinished()
70→{
71→	// 确保精确到达目标位置
72→	SetActorLocation(MoveTargetLocation);
73→	bIsMoving = false;
74→
75→	// 清理 Timeline（防止下次移动时叠加回调）
76→	MoveTimeline.SetTimelineFinishedFunc(FOnTimelineEvent());
77→	// 清理所有 InterpFloat
78→	MoveTimeline = FTimeline();
79→
80→	OnMoveComplete.Broadcast();
81→}
