431→bool ALFPWorldMapManager::LoadNodesFromCSV(const FString& FilePath)
432→{
433→	FString CSVContent;
434→	if (!FFileHelper::LoadFileToString(CSVContent, *FilePath))
435→	{
436→		UE_LOG(LogTemp, Error, TEXT("LoadNodesFromCSV: 无法加载文件 %s"), *FilePath);
437→		return false;
438→	}
439→
440→	// 使用临时 DataTable 解析 CSV
441→	UDataTable* TempTable = NewObject<UDataTable>(GetTransientPackage());
442→	TempTable->RowStruct = FLFPWorldNodeRow::StaticStruct();
443→
444→	TArray<FString> Problems = TempTable->CreateTableFromCSVString(CSVContent);
445→	if (Problems.Num() > 0)
446→	{
447→		for (const FString& Problem : Problems)
448→		{
449→			UE_LOG(LogTemp, Warning, TEXT("节点 CSV 解析问题: %s"), *Problem);
450→		}
451→	}
452→
453→	TArray<FLFPWorldNodeRow*> AllRows;
454→	TempTable->GetAllRows<FLFPWorldNodeRow>(TEXT("LoadNodes"), AllRows);
455→
456→	for (const FLFPWorldNodeRow* Row : AllRows)
457→	{
458→		if (!Row) continue;
459→
460→		ALFPWorldMapNode* Node = SpawnNode(Row->NodeID, FVector2D(Row->PosX, Row->PosY), Row->NodeType);
461→		if (Node)
462→		{
463→			Node->InitFromRowData(*Row);
464→		}
465→	}
466→
467→	UE_LOG(LogTemp, Log, TEXT("LoadNodesFromCSV: 加载了 %d 个节点"), AllRows.Num());
468→	return true;
469→}
