420→void ALFPWorldMapPlayerController::EnterNode(ALFPWorldMapNode* Node)
421→{
422→	if (!Node) return;
423→
424→	UE_LOG(LogTemp, Log, TEXT("进入节点 %d，类型: %d"), Node->NodeID, (int32)Node->NodeType);
425→
426→	switch (Node->NodeType)
427→	{
428→	case ELFPWorldNodeType::WNT_Battle:
429→	case ELFPWorldNodeType::WNT_Boss:
430→		EnterBattle(Node);
431→		break;
432→
433→	case ELFPWorldNodeType::WNT_Event:
434→		// TODO: 触发事件系统
435→		UE_LOG(LogTemp, Log, TEXT("事件节点 %d: EventID=%s"), Node->NodeID, *Node->EventID);
436→		break;
437→
438→	case ELFPWorldNodeType::WNT_Shop:
439→		// TODO: 打开商店 UI
440→		UE_LOG(LogTemp, Log, TEXT("商店节点 %d"), Node->NodeID);
441→		break;
442→
443→	case ELFPWorldNodeType::WNT_Town:
444→		// TODO: 进入城镇
445→		UE_LOG(LogTemp, Log, TEXT("城镇节点 %d"), Node->NodeID);
446→		break;
447→
448→	case ELFPWorldNodeType::WNT_QuestNPC:
449→		// TODO: 触发任务对话
450→		UE_LOG(LogTemp, Log, TEXT("任务NPC节点 %d"), Node->NodeID);
451→		break;
452→
453→	case ELFPWorldNodeType::WNT_SkillNode:
454→		// TODO: 打开技能树 UI
455→		UE_LOG(LogTemp, Log, TEXT("技能节点 %d"), Node->NodeID);
456→		break;
457→
458→	case ELFPWorldNodeType::WNT_EvolutionTower:
459→		OpenEvolutionTower();
460→		break;
461→
462→	default:
463→		break;
464→	}
465→}
