513→ALFPWorldMapManager* ALFPWorldMapPlayerController::GetWorldMapManager() const
514→{
515→	if (!CachedWorldMapManager)
516→	{
517→		TArray<AActor*> Managers;
518→		UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPWorldMapManager::StaticClass(), Managers);
519→		if (Managers.Num() > 0)
520→		{
521→			CachedWorldMapManager = Cast<ALFPWorldMapManager>(Managers[0]);
522→		}
523→	}
524→	return CachedWorldMapManager;
