527→void ALFPWorldMapPlayerController::OnPawnMoveCompleted()
528→{
529→	// 解绑回调
530→	if (ALFPWorldMapManager* Manager = GetWorldMapManager())
531→	{
532→		if (ALFPWorldMapPawn* MapPawn = Manager->GetPlayerPawn())
533→		{
534→			MapPawn->OnMoveComplete.RemoveDynamic(this, &ALFPWorldMapPlayerController::OnPawnMoveCompleted);
535→		}
536→	}
537→
538→	// 显示新的可达节点
539→	ShowReachableNodes();
540→
541→	// 自动进入目标节点
542→	if (PendingEnterNode)
543→	{
544→		ALFPWorldMapNode* NodeToEnter = PendingEnterNode;
545→		PendingEnterNode = nullptr;
546→		EnterNode(NodeToEnter);
547→	}
548→}
