550→void ALFPWorldMapPlayerController::OpenEvolutionTower()
551→{
552→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
553→	if (!GI || !UnitMergeWidgetClass) return;
554→
555→	if (!UnitMergeWidget)
556→	{
557→		UnitMergeWidget = CreateWidget<ULFPUnitMergeWidget>(this, UnitMergeWidgetClass);
558→		if (UnitMergeWidget)
559→		{
560→			UnitMergeWidget->OnClosed.AddDynamic(this, &ALFPWorldMapPlayerController::OnUnitMergeWidgetClosed);
561→			UnitMergeWidget->AddToViewport();
562→		}
563→	}
564→	else
565→	{
566→		UnitMergeWidget->SetVisibility(ESlateVisibility::Visible);
567→		UnitMergeWidget->AddToViewport();
568→	}
569→
570→	if (UnitMergeWidget)
571→	{
572→		UnitMergeWidget->Setup(GI, GI->UnitRegistry);
573→	}
574→}
