 90→ALFPWorldMapNode* ULFPWorldMapEditorComponent::PlaceNodeAt(FVector2D WorldPos)
 91→{
 92→	if (!bEditorActive) return nullptr;
 93→
 94→	ALFPWorldMapManager* Manager = GetWorldMapManager();
 95→	if (!Manager) return nullptr;
 96→
 97→	int32 NewID = Manager->GetNextNodeID();
 98→	ALFPWorldMapNode* NewNode = Manager->SpawnNode(NewID, WorldPos, BrushNodeType);
 99→
100→	if (NewNode)
101→	{
102→		// 编辑器模式下新节点直接可见
103→		NewNode->bIsRevealed = true;
104→		NewNode->UpdateVisualState();
105→
106→		// 应用笔刷参数
107→		NewNode->BattleMapName = BrushBattleMapName;
108→		NewNode->StarRating = BrushStarRating;
109→		NewNode->bCanEscape = BrushCanEscape;
110→		NewNode->EventID = BrushEventID;
111→		NewNode->BaseGoldReward = BrushBaseGoldReward;
112→		NewNode->BaseFoodReward = BrushBaseFoodReward;
113→
114→		UE_LOG(LogTemp, Log, TEXT("放置节点 ID %d 在 (%.1f, %.1f)"), NewID, WorldPos.X, WorldPos.Y);
115→	}
116→
117→	return NewNode;
118→}
