126→{
127→	bIsDragging = false;
128→	if (DragTime > DragThresholdTime)
129→	{
130→		DragTime = 0.f;
131→		return;
132→	}
133→	DragTime = 0.f;
134→
135→	// 编辑器模式优先处理
136→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
137→	{
138→		// 射线检测点击的节点
139→		FHitResult HitResult;
140→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
141→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
142→
143→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
144→
145→		switch (CurrentTool)
146→		{
147→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
148→			{
149→				// 射线投射到 Z=0 平面获取世界坐标
150→				FVector WorldOrigin, WorldDirection;
151→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
152→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
153→				{
154→					float T = -WorldOrigin.Z / WorldDirection.Z;
155→					FVector HitPoint = WorldOrigin + WorldDirection * T;
156→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
157→				}
158→			}
159→			break;
160→
161→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
162→			if (ClickedNode)
163→			{
164→				WorldMapEditorComponent->SelectNode(ClickedNode);
165→				WorldMapEditorComponent->RemoveSelectedNode();
166→			}
167→			break;
168→
169→		case ELFPWorldMapEditorTool::WMET_MoveNode:
170→			if (ClickedNode)
171→			{
172→				WorldMapEditorComponent->SelectNode(ClickedNode);
173→			}
174→			else if (WorldMapEditorComponent->GetSelectedNode())
175→			{
176→				// 移动到点击位置
177→				FVector WorldOrigin, WorldDirection;
178→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
179→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
180→				{
181→					float T = -WorldOrigin.Z / WorldDirection.Z;
182→					FVector HitPoint = WorldOrigin + WorldDirection * T;
183→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
184→				}
185→			}
186→			break;
187→
188→		case ELFPWorldMapEditorTool::WMET_ConnectEdge:
189→			if (ClickedNode)
190→			{
191→				WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
192→			}
193→			break;
194→
195→		case ELFPWorldMapEditorTool::WMET_RemoveEdge:
196→			if (ClickedNode)
197→			{
198→				WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
199→			}
200→			break;
201→
202→		case ELFPWorldMapEditorTool::WMET_SetNodeParams:
203→			if (ClickedNode)
204→			{
205→				WorldMapEditorComponent->SelectNode(ClickedNode);
206→				WorldMapEditorComponent->ApplyParamsToSelectedNode();
207→			}
208→			break;
209→
210→		default:
211→			break;
212→		}
213→		return;
214→	}
215→
216→	// 游戏模式：棋子移动中屏蔽点击
217→	ALFPWorldMapManager* Manager = GetWorldMapManager();
218→	if (Manager && Manager->IsPawnMoving()) return;
219→
220→	// 游戏模式：点击节点移动或进入
221→	FHitResult HitResult;
222→	GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
223→	ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
224→
225→	if (ClickedNode)
226→	{
227→		if (!Manager || !Manager->GetPlayerState()) return;
228→
229→		int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
230→
231→		// 点击当前节点 → 进入节点
232→		if (ClickedNode->NodeID == CurrentNodeID)
233→		{
234→			EnterNode(ClickedNode);
235→			return;
236→		}
237→
238→		// 点击相邻可达节点 → 移动
239→		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
240→		if (ReachableIDs.Contains(ClickedNode->NodeID))
241→		{
242→			MoveToNode(ClickedNode);
243→		}
244→		else
245→		{
246→			// 不可达，只选中
247→			SelectNode(ClickedNode);
248→		}
249→	}
250→}
